const config = $('Set Config1').first().json;
const domain = config.freshservice_domain ?? $json.freshservice_domain;
const apiKey = config.freshservice_api_key ?? $json.freshservice_api_key;

if (!domain) {
  throw new Error('Missing freshservice_domain in Set Config');
}
if (!apiKey) {
  throw new Error('Missing freshservice_api_key in Set Config');
}

const authHeader = 'Basic ' + Buffer.from(`${apiKey}:X`).toString('base64');

function isUnresolved(ticket) {
  return [2, 3].includes(Number(ticket?.status));
}

async function fetchAllTickets() {
  const allTickets = [];
  let page = 1;
  const perPage = 100;

  while (page <= 200) {
    let payload;
    try {
      payload = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://${domain}/api/v2/tickets`,
        qs: {
          per_page: perPage,
          page
        },
        headers: {
          Authorization: authHeader,
          Accept: 'application/json'
        },
        json: true
      });
    } catch (error) {
      throw new Error(`Freshservice tickets API failed on page ${page}: ${error.message}`);
    }

    const tickets = payload.tickets ?? payload.results ?? [];
    allTickets.push(...tickets);

    if (tickets.length < perPage) break;
    page += 1;
  }

  return allTickets;
}

const allTickets = await fetchAllTickets.call(this);
const unresolvedTickets = allTickets.filter(isUnresolved);

return [{
  json: {
    tickets: unresolvedTickets
  }
}];

