function hasSlaBreach(ticket) {
  return Boolean(ticket?.sla_breached || ticket?.is_escalated || ticket?.fr_escalated || ticket?.escalated);
}

async function fetchAllTickets() {
  const allTickets = [];
  let page = 1;
  const perPage = 100;

  while (page <= 200) {
    let payload;
    try {
      payload = await this.helpers.httpRequest({
