const allTickets = await fetchAllTickets.call(this);
const breachedUnresolved = allTickets.filter((ticket) => isUnresolved(ticket) && hasSlaBreach(ticket));

return [{
  json: {
    tickets: breachedUnresolved
  }
}];

const unresolvedResponse = $items('Get Unresolved Tickets1', 0, 0)[0]?.json ?? {};
const config = $('Set Config1').first().json;

const domain = config.freshservice_domain ?? $json.freshservice_domain;
const apiKey = config.freshservice_api_key ?? $json.freshservice_api_key;

if (!domain) {
  throw new Error('Missing freshservice_domain in Set Config');
}
if (!apiKey) {
  throw new Error('Missing freshservice_api_key in Set Config');
}

const authHeader = 'Basic ' + Buffer.from(`${apiKey}:X`).toString('base64');
const unresolved = unresolvedResponse.tickets ?? unresolvedResponse.results ?? [];

const now = new Date();
const statusMap = {
  2: 'Open',
  3: 'Pending',
  4: 'Resolved',
  5: 'Closed'
};
const priorityMap = {
  1: 'Low',
  2: 'Medium',
  3: 'High',
  4: 'Urgent'
};

const groupCache = new Map();
const agentCache = new Map();
const requesterCache = new Map();
const companyCache = new Map();

function agingBucket(days) {
  if (days <= 2) return '0-2 days';
  if (days <= 7) return '3-7 days';
  if (days <= 14) return '8-14 days';
  return '15+ days';
}

async function fetchEntity(resource, id, entityKey) {
  if (!id) {
    return null;
  }
  try {
    const payload = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://${domain}/api/v2/${resource}/${id}`,
      headers: {
        Authorization: authHeader,
        Accept: 'application/json'
      },
      json: true
    });
    return payload?.[entityKey] ?? null;
  } catch (error) {
    return null;
  }
}

async function getGroupName(groupId) {
  if (!groupId) return '';
  const key = String(groupId);
  if (groupCache.has(key)) return groupCache.get(key);
  const group = await fetchEntity.call(this, 'groups', groupId, 'group');
  const name = group?.name ?? `Group #${groupId}`;
  groupCache.set(key, name);
  return name;
}

async function getAgentName(agentId) {
  if (!agentId) return '';
  const key = String(agentId);
  if (agentCache.has(key)) return agentCache.get(key);
  const agent = await fetchEntity.call(this, 'agents', agentId, 'agent');
  const derivedName = agent?.name ?? agent?.contact?.name ?? [agent?.first_name, agent?.last_name].filter(Boolean).join(' ').trim();
  const name = derivedName || `Agent #${agentId}`;
  agentCache.set(key, name);
  return name;
}

async function getRequester(requesterId) {
  if (!requesterId) return null;
  const key = String(requesterId);
  if (requesterCache.has(key)) return requesterCache.get(key);
  let requester = await fetchEntity.call(this, 'requesters', requesterId, 'requester');
  if (!requester) {
    requester = await fetchEntity.call(this, 'contacts', requesterId, 'contact');
  }
  requesterCache.set(key, requester);
  return requester;
}

async function getCompanyName(companyId) {
  if (!companyId) return '';
  const key = String(companyId);
  if (companyCache.has(key)) return companyCache.get(key);
  const company = await fetchEntity.call(this, 'companies', companyId, 'company');
  const name = company?.name ?? `Company #${companyId}`;
  companyCache.set(key, name);
  return name;
}

const rows = [];
for (const t of unresolved) {
  const created = t.created_at ? new Date(t.created_at) : null;
  const ageDays = created ? Math.max(0, Math.floor((now - created) / (1000 * 60 * 60 * 24))) : null;
  const hasFrSlaBreach = Boolean(t?.fr_escalated);
  const hasResSlaBreach = Boolean(t?.sla_breached || t?.is_escalated || t?.escalated);

  const requester = await getRequester.call(this, t.requester_id);
  const groupName = await getGroupName.call(this, t.group_id);
  const agentName = await getAgentName.call(this, t.responder_id);
  const companyName = await getCompanyName.call(this, t.company_id ?? requester?.company_id);

  rows.push({
    ticket_id: t.id,
    subject: t.subject ?? '',
    status: statusMap[t.status] ?? String(t.status ?? ''),
    priority: priorityMap[t.priority] ?? String(t.priority ?? ''),
    group: groupName,
    company: companyName,
    agent: agentName,
    requester: (requester?.name ?? requester?.contact?.name ?? [requester?.first_name, requester?.last_name].filter(Boolean).join(' ').trim()) || `Requester #${t.requester_id ?? ''}`,
    created_at: t.created_at ?? '',
    due_by: t.due_by ?? '',
    fr_due_by: t.fr_due_by ?? '',
    age_days: ageDays,
    aging_bucket: ageDays === null ? 'unknown' : agingBucket(ageDays),
    fr_sla_breach: hasFrSlaBreach ? 'yes' : 'no',
    res_sla_breach: hasResSlaBreach ? 'yes' : 'no',
    ticket_type: t.type ?? ''
  });
}

const summary = {
  generated_on: now.toISOString(),
  unresolved_total: rows.length,
  incidents_total: rows.filter((r) => r.ticket_type === 'Incident').length,
  service_requests_total: rows.filter((r) => r.ticket_type === 'Service Request').length,
  sla_breached_total: rows.filter((r) => r.fr_sla_breach === 'yes' || r.res_sla_breach === 'yes').length,
  aging_0_2: rows.filter((r) => r.aging_bucket === '0-2 days').length,
  aging_3_7: rows.filter((r) => r.aging_bucket === '3-7 days').length,
  aging_8_14: rows.filter((r) => r.aging_bucket === '8-14 days').length,
  aging_15_plus: rows.filter((r) => r.aging_bucket === '15+ days').length
};

return rows.map((row) => ({
  json: {
    ...row,
    summary,
    report_date: config.report_date
  }
}));

const rows = $input.all();

return rows.map((item) => ({
  json: {
    ticket_id: item.json.ticket_id ?? '',
    subject: item.json.subject ?? '',
    status: item.json.status ?? '',
    priority: item.json.priority ?? '',
    group: item.json.group ?? '',
    company: item.json.company ?? '',
    agent: item.json.agent ?? '',
    requester: item.json.requester ?? '',
    created_at: item.json.created_at ?? '',
    due_by: item.json.due_by ?? '',
    fr_due_by: item.json.fr_due_by ?? '',
    age_days: item.json.age_days ?? '',
    fr_sla_breach: item.json.fr_sla_breach ?? '',
    res_sla_breach: item.json.res_sla_breach ?? ''
  }
}));

const excelInput = $input.first();
const excelBinary = excelInput?.binary?.data;
if (!excelBinary) {
  throw new Error('Missing Excel binary from Create Excel Report1');
}

const rowsInput = $items('Normalize and Score Tickets1', 0, 0) ?? [];
if (!rowsInput.length) {
  return [];
}

const rows = rowsInput.map((item) => item.json);
const summary = rows[0].summary;
const reportDate = rows[0].report_date || new Date().toISOString().slice(0, 10);

const top25 = rows
  .sort((a, b) => (b.age_days ?? 0) - (a.age_days ?? 0))
  .slice(0, 25);

const tableStyle = `
  border-collapse: collapse;
  width: 100%;
  font-family: Calibri, Arial, sans-serif;
  font-size: 11pt;
`;
const thStyle = `
  background-color: #1F4E79;
  color: #ffffff;
  border: 1px solid #000;
  padding: 6px 8px;
  text-align: left;
`;
const tdStyle = `border: 1px solid #999; padding: 5px 8px;`;
const tdBreachedStyle = `border: 1px solid #999; padding: 5px 8px; background-color: #FFCCCC; color: #CC0000; font-weight: bold;`;
const tdAltStyle = `border: 1px solid #999; padding: 5px 8px; background-color: #F5F5F5;`;

const ticketRows = top25.map((t, i) => {
  const isBreached = t.fr_sla_breach === 'yes' || t.res_sla_breach === 'yes';
  const rowBg = i % 2 === 0 ? tdStyle : tdAltStyle;
  const breachedCell = isBreached ? tdBreachedStyle : rowBg;
  return `<tr>
    <td style="${rowBg}">${i + 1}</td>
    <td style="${rowBg}">${t.ticket_id ?? ''}</td>
    <td style="${rowBg}">${escapeHtml(t.subject ?? '')}</td>
    <td style="${rowBg}">${t.status ?? ''}</td>
    <td style="${rowBg}">${t.priority ?? ''}</td>
    <td style="${rowBg}">${t.age_days ?? ''}</td>
    <td style="${rowBg}">${t.aging_bucket ?? ''}</td>
    <td style="${breachedCell}">${isBreached ? 'YES' : 'No'}</td>
    <td style="${rowBg}">${t.due_by ? t.due_by.slice(0, 10) : ''}</td>
  </tr>`;
}).join('\n');

function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

const html = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
<head>
  <meta charset='UTF-8'>
  <title>Freshservice Ticket Report</title>
  <!--[if gte mso 9]><xml><w:WordDocument><w:View>Print</w:View></w:WordDocument></xml><![endif]-->
  <style>
    body { font-family: Calibri, Arial, sans-serif; font-size: 11pt; margin: 20px; }
    h1 { color: #1F4E79; font-size: 18pt; }
    h2 { color: #1F4E79; font-size: 14pt; margin-top: 20px; }
    p { font-size: 10pt; color: #555; }
    .summary-table { border-collapse: collapse; width: 320px; margin-bottom: 20px; font-family: Calibri, Arial, sans-serif; font-size: 11pt; }
    .summary-table th { background-color: #2E75B6; color: #fff; border: 1px solid #000; padding: 6px 10px; text-align: left; }
    .summary-table td { border: 1px solid #999; padding: 5px 10px; }
    .summary-table tr:nth-child(even) td { background-color: #DEEAF1; }
  </style>
</head>
<body>
  <h1>Freshservice Ticket Report</h1>
  <p>Generated on: ${summary.generated_on}</p>

  <h2>Summary</h2>
  <table class="summary-table">
    <thead><tr><th>Metric</th><th>Count</th></tr></thead>
    <tbody>
      <tr><td>Unresolved tickets</td><td>${summary.unresolved_total}</td></tr>
      <tr><td>Incidents</td><td>${summary.incidents_total}</td></tr>
      <tr><td>Service Requests</td><td>${summary.service_requests_total}</td></tr>
      <tr><td>SLA breached tickets</td><td>${summary.sla_breached_total}</td></tr>
      <tr><td>Aging 0-2 days</td><td>${summary.aging_0_2}</td></tr>
      <tr><td>Aging 3-7 days</td><td>${summary.aging_3_7}</td></tr>
      <tr><td>Aging 8-14 days</td><td>${summary.aging_8_14}</td></tr>
      <tr><td>Aging 15+ days</td><td>${summary.aging_15_plus}</td></tr>
    </tbody>
  </table>

  <h2>Top 25 Oldest Unresolved Tickets</h2>
  <table style="${tableStyle}">
    <thead>
      <tr>
        <th style="${thStyle}">#</th>
        <th style="${thStyle}">Ticket ID</th>
        <th style="${thStyle}">Subject</th>
        <th style="${thStyle}">Status</th>
        <th style="${thStyle}">Priority</th>
        <th style="${thStyle}">Age (days)</th>
        <th style="${thStyle}">Aging Bucket</th>
        <th style="${thStyle}">SLA Breached</th>
        <th style="${thStyle}">Due By</th>
      </tr>
    </thead>
    <tbody>
      ${ticketRows}
    </tbody>
  </table>
</body>
</html>`;

return [{
  json: {
    report_date: reportDate
  },
  binary: {
    excel: excelBinary,
    word: {
      data: Buffer.from(html, 'utf8').toString('base64'),
      mimeType: 'application/msword',
      fileName: `freshservice-summary-${reportDate}.doc`
    }
  }
}];
